import java.util.*;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.JsonNode;
public class JwtDecoder {
    static final ObjectMapper MAPPER = new ObjectMapper();

    static String decodePayload(String jwtToken) throws Exception {
        // Split header.payload.signature:
        String[] parts = jwtToken.split("\\.");
        if (parts.length != 3) throw new IllegalArgumentException("Not a JWT");

        // Decode payload (second part) — base64url:
        byte[] payloadBytes = Base64.getUrlDecoder().decode(parts[1]);
        String payloadJson = new String(payloadBytes);

        // Parse JSON and extract subject:
        JsonNode payload = MAPPER.readTree(payloadJson);
        return payload.path("sub").asText();
    }

    public static void main(String[] args) throws Exception {
        // Simulated JWT with payload: {"sub":"aisha","roles":["USER"]}
        String fakeJwt = "header.eyJzdWIiOiJhaXNoYSIsInJvbGVzIjpbIlVTRVIiXX0.signature";
        System.out.println("Subject: " + decodePayload(fakeJwt));
    }
}

