import io.jsonwebtoken.*;
import io.jsonwebtoken.security.Keys;
import java.security.Key;
import java.util.Date;
import javax.crypto.SecretKey;
import org.springframework.stereotype.Service;

@Service
public class JwtService {
    // In production: @Value('${jwt.secret}') — never hardcode!
    private static final String SECRET = "dGhpcyBpcyBhIHZlcnkgc2VjdXJlIGtleQ==";
    private static final long EXPIRY_MS = 86_400_000L;  // 24 hours

    private SecretKey signingKey() {
        return Keys.hmacShaKeyFor(Base64.getDecoder().decode(SECRET));
    }

    public String generateToken(String username) {
        return Jwts.builder()
            .subject(username)
            .issuedAt(new Date())
            .expiration(new Date(System.currentTimeMillis() + EXPIRY_MS))
            .signWith(signingKey())
            .compact();
    }

    public String extractUsername(String token) {
        return Jwts.parser()
            .verifyWith(signingKey())
            .build()
            .parseSignedClaims(token)
            .getPayload()
            .getSubject();
    }
}

// Additional method in JwtService:

public boolean isValid(String token, org.springframework.security.core.userdetails.UserDetails userDetails) {
    try {
        Claims claims = Jwts.parser()
            .verifyWith(signingKey())
            .build()
            .parseSignedClaims(token)
            .getPayload();

        String username = claims.getSubject();
        Date expiry = claims.getExpiration();

        return username.equals(userDetails.getUsername())
            && expiry.after(new Date());
    } catch (JwtException e) {
        // Expired, tampered, or invalid format — not valid
        return false;
    }
}

