import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;
import org.springframework.http.*;
import org.springframework.security.access.AccessDeniedException;

@RestController @RequestMapping("/api")
public class UserProfileController {
    private final AppUserRepository userRepo;
    UserProfileController(AppUserRepository r) { userRepo=r; }

    @GetMapping("/me")
    public ResponseEntity<AppUser> getMe(Authentication auth) {
        // auth.getName() = the username from JWT subject
        return userRepo.findByUsername(auth.getName())
            .map(ResponseEntity::ok)
            .orElse(ResponseEntity.notFound().build());
    }

    @GetMapping("/users/{id}")
    public ResponseEntity<AppUser> getUser(
            @PathVariable String id,
            Authentication auth) {
        AppUser requester = userRepo.findByUsername(auth.getName()).orElseThrow();
        AppUser target    = userRepo.findById(id)
            .orElseThrow(() -> new ResourceNotFoundException("User",id));

        boolean isAdmin = auth.getAuthorities().stream()
            .anyMatch(a -> a.getAuthority().equals("ROLE_ADMIN"));

        // Only admin or the user themselves can see the profile:
        if (!isAdmin && !requester.getId().equals(id)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN).build();
        }
        return ResponseEntity.ok(target);
    }
}

