@PostMapping("/register")
public ResponseEntity<RegisterResponse> register(@RequestBody RegisterRequest req) {
    // Check username taken:
    if (userRepo.existsByUsername(req.username())) {
        return ResponseEntity.status(HttpStatus.CONFLICT).build();
    }

    // Hash password — NEVER store plain text:
    String hashedPassword = passwordEncoder.encode(req.password());

    // Save new user:
    AppUser newUser = new AppUser(req.username(), hashedPassword, "USER");
    AppUser saved = userRepo.save(newUser);

    // Generate JWT immediately:
    String token = jwtService.generateToken(saved.getUsername(), List.of("ROLE_USER"));

    return ResponseEntity.status(HttpStatus.CREATED)
        .body(new RegisterResponse(saved.getId(), saved.getUsername(), token));
}

