    }

    @Test void protectedEndpoint_withToken_200() {
        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(userToken);
        var resp = rest.exchange("/api/products", HttpMethod.POST,
            new HttpEntity<>(Map.of("name","Mouse","price",799.0,"category","Elec","stockQty",5), headers),
            java.util.LinkedHashMap.class);
